input.new_string:
/** A live cell at coordinates (x, y). */
export type Cell = [number, number];

const areNeighbors = (a: Cell, b: Cell): boolean => {
  const [ax, ay] = a;
  const [bx, by] = b;
  if (ax === bx && ay === by) return false;
  return Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
};

const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
  liveCells.filter((other) => areNeighbors(cell, other)).length;

const survives = (cell: Cell, liveCells: Cell[]): boolean => {
  const neighbors = countLiveNeighbors(cell, liveCells);
  return neighbors === 2 || neighbors === 3;
};

/**
 * Computes the next generation of Conway's Game of Life
 * from the currently live cells.
 */
export function nextGeneration(liveCells: Cell[]): Cell[] {
  return liveCells.filter((cell) => survives(cell, liveCells));
}

